SELECT * FROM (


    T.SDGHJE != '0' AND T.JSBJ IN ('Y', 'S', 'W')

        AND T.HKPCH = #{req.hkpch}


        AND T.DWDM = #{req.deptId}


        AND T.SDGHZH = #{req.zh}


GROUP BY T.HKPCH

UNION ALL



    T.SDGHJE != '0' AND T.JSBJ IN ('Y', 'S', 'W')

        AND T.HKPCH = #{req.hkpch}


        AND T.DWDM = #{req.deptId}


        AND T.SDGHZH = #{req.zh}


) AS combined_result

